    try {
      const [jobsRes, statsRes] = await Promise.all([getJobs(), getRecruiterStats()]);
      setJobs(jobsRes.data.filter(j => j.recruiterId === user.id));
      setStats(statsRes.data);
    } catch (err) {
      console.error(err);
    }
  };

