                           <h3 className="text-xl font-black text-white mb-10 flex items-center gap-4 uppercase"><Sparkles className="w-6 h-6 text-indigo-400" /> AI Suggestions</h3>
                           <div className="space-y-6">
                              {matches.map(m => (
                                 <div key={m.id} className="p-6 rounded-[24px] bg-slate-900/60 border border-slate-800 shadow-inner group hover:border-indigo-500/30 transition-all">
                                    <div className="flex items-center justify-between mb-4">
                                       <div>
                                          <p className="text-sm font-black text-white uppercase tracking-tight truncate w-32">{m.name}</p>
                                          <p className="text-[10px] text-slate-500 font-bold uppercase mt-1">MATCH: {m.matchScore}%</p>
                                       </div>
                                       <button onClick={() => handleAssign(m.id)} className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg active:scale-90 transition-all"><UserPlus className="w-5 h-5" /></button>
                                    </div>
                                 </div>
                              ))}
                           </div>
                        </div>
                     </div>
                  </div>
               )}
            </div>
          )}
        </div>
      </main>
    </div>
  );
}

