import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { getJobs, applyToJob, getMyApplications, analyzeProfile, updateProfile, getNotifications } from '../services/api';
import { LogOut, GraduationCap, Briefcase, BarChart3, Bell, User, Sparkles, Code, Globe, FileText, Plus, X, Send, CheckCircle, Clock, XCircle, ChevronRight, TrendingUp, Target, Zap, BookOpen } from 'lucide-react';

export default function StudentDashboard() {
  const { user, logout, updateUser } = useAuth();
  const [activeTab, setActiveTab] = useState('dashboard');
  const [jobs, setJobs] = useState([]);
  const [myApps, setMyApps] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [analyzing, setAnalyzing] = useState(false);
  const [toast, setToast] = useState(null);

  // Profile form state
  const [skills, setSkills] = useState(user?.skills || []);
  const [newSkill, setNewSkill] = useState('');
  const [githubLink, setGithubLink] = useState(user?.githubLink || '');
  const [portfolioLink, setPortfolioLink] = useState(user?.portfolioLink || '');
  const [resume, setResume] = useState(user?.resume || '');
  const [leetcode, setLeetcode] = useState(user?.leetcodeStats || { solved: 0, easy: 0, medium: 0, hard: 0 });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [jobsRes, appsRes, notifsRes] = await Promise.all([
        getJobs(),
        getMyApplications(),
        getNotifications()
      ]);
      setJobs(jobsRes.data);
      setMyApps(appsRes.data);
      setNotifications(notifsRes.data);
    } catch (err) {
      console.error(err);
    }
  };

  const showToast = (message, type = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleSaveProfile = async () => {
    try {
      const res = await updateProfile({ skills, githubLink, portfolioLink, resume, leetcodeStats: leetcode });
      updateUser(res.data);
      showToast('Profile updated successfully!');
    } catch (err) {
      showToast('Failed to update profile', 'error');
    }
  };

  const handleAnalyze = async () => {
    setAnalyzing(true);
    try {
      await handleSaveProfile();
      const res = await analyzeProfile();
      updateUser(res.data.user);
      showToast('Profile analyzed successfully! Check your scores.');
      setActiveTab('scores');
    } catch (err) {
      showToast('Analysis failed', 'error');
    }
    setAnalyzing(false);
  };

  const handleApply = async (jobId) => {
    try {
      await applyToJob(jobId);
      showToast('Application submitted successfully!');
      loadData();
    } catch (err) {
      showToast(err.response?.data?.error || 'Failed to apply', 'error');
    }
  };

  const addSkill = () => {
    if (newSkill.trim() && !skills.includes(newSkill.trim())) {
      setSkills([...skills, newSkill.trim()]);
      setNewSkill('');
    }
  };

  const removeSkill = (skillToRemove) => {
    setSkills(skills.filter(s => s !== skillToRemove));
  };

  const appliedJobIds = myApps.map(a => a.jobId);
  const scores = user?.scores;

  const tabs = [
    { id: 'dashboard', label: 'Dashboard', icon: BarChart3 },
    { id: 'profile', label: 'Profile', icon: User },
    { id: 'scores', label: 'AI Scores', icon: Sparkles },
    { id: 'jobs', label: 'Jobs', icon: Briefcase },
    { id: 'applications', label: 'Applications', icon: FileText },
