              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-black text-white truncate leading-tight uppercase tracking-tight">{user?.name}</p>
                <p className="text-[10px] font-black text-slate-500 truncate uppercase tracking-[0.1em] mt-1.5 opacity-60">{user?.email?.split('@')[0]}</p>
              </div>
            </div>
            <button onClick={logout}
              className="w-full flex items-center justify-center gap-3 px-5 py-3.5 rounded-[18px] bg-slate-900 border border-slate-800 text-slate-400 hover:text-white hover:border-red-500/50 hover:bg-red-500/10 transition-all text-xs font-black uppercase tracking-[0.15em] shadow-sm">
              <LogOut className="w-4 h-4" />
              TERMINATE
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto relative">
        {/* Toast */}
        {toast && (
          <div className={`fixed top-8 right-8 z-50 toast-enter px-8 py-4 rounded-2xl flex items-center gap-3 text-sm font-black shadow-2xl animate-fade-in ${
            toast.type === 'error' ? 'bg-red-500/90 text-white' : 'bg-emerald-500/90 text-white'
          }`}>
            {toast.type === 'error' ? <XCircle className="w-5 h-5" /> : <CheckCircle className="w-5 h-5" />}
            {toast.message.toUpperCase()}
          </div>
        )}

        <div className="p-12 max-w-[1400px] mx-auto">
          {/* Dashboard Tab */}
          {activeTab === 'dashboard' && (
            <div className="animate-fade-in">
              <div className="mb-14 lg:flex items-end justify-between">
                <div>
                  <h2 className="text-6xl font-black text-white tracking-tight mb-4">Core <span className="gradient-text">Intelligence</span> 👋</h2>
                  <p className="text-xl text-slate-400 font-medium">Your personalized AI-driven placement ecosystem is active.</p>
                </div>
                <div className="hidden lg:flex items-center gap-5">
                  <div className="text-right">
                    <p className="text-xs font-black text-slate-500 uppercase tracking-[0.2em] leading-none mb-2 opacity-60">Sync State</p>
                    <p className="text-sm font-black text-slate-200">ACTIVE_NODE_01</p>
                  </div>
                  <div className="w-14 h-14 rounded-2xl bg-slate-900 border border-slate-800 flex items-center justify-center shadow-xl">
                    <Clock className="w-6 h-6 text-slate-500" />
                  </div>
                </div>
              </div>

              {/* Stats Cards */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 mb-16">
                {[
                  { label: 'Intelligence Index', value: scores?.finalScore || '0', icon: Zap, color: 'indigo', subtitle: 'Global Perc: 95%' },
                  { label: 'Active Pipeline', value: myApps.length, icon: Send, color: 'emerald', subtitle: 'Target: 5 Benchmarks' },
                  { label: 'Technical Rank', value: leetcode?.solved || '0', icon: Code, color: 'blue', subtitle: 'Algorithmic Mastery' },
                  { label: 'Market Reach', value: jobs.filter(j => j.status === 'open').length, icon: Globe, color: 'purple', subtitle: 'Global Opportunities' },
                ].map((stat, i) => (
                  <div key={i} className="glass-card p-8 premium-border group shadow-xl" style={{ animationDelay: `${i * 0.1}s` }}>
