                    <p className="text-xl text-slate-400 mb-12 max-w-2xl leading-relaxed font-medium">
                      Our proprietary neural engine identifies semantic patterns in your professional data, matching you with top-tier roles at scale.
                    </p>
                    <button onClick={() => setActiveTab('profile')} className="glow-btn px-12 py-5 text-sm font-black tracking-[0.2em] flex items-center gap-4 shadow-2xl">
                      <Target className="w-5 h-5" />
                      SYNC PROFILE DATA
                    </button>
                  </div>
                </div>

                <div className="glass-card p-10 premium-border flex flex-col shadow-2xl">
                  <div className="flex items-center justify-between mb-10">
