                  </div>
                  <div className="space-y-5 flex-1">
                    {jobs.filter(j => j.status === 'open').slice(0, 5).map(job => (
                      <div key={job.id} onClick={() => setActiveTab('jobs')} className="flex items-center justify-between p-5 rounded-[24px] bg-slate-900/50 border border-slate-800 hover:border-indigo-500/50 hover:bg-slate-900/80 transition-all cursor-pointer group shadow-sm">
                        <div className="flex items-center gap-5">
                          <div className="w-12 h-12 rounded-xl bg-slate-800 flex items-center justify-center font-black text-indigo-400 text-lg shadow-inner">
                            {job.company.charAt(0)}
                          </div>
                          <div>
                            <p className="text-sm font-black text-white group-hover:text-indigo-400 transition-colors uppercase tracking-tight">{job.role}</p>
