                              <p className="text-xs font-black text-white uppercase tracking-widest leading-tight">{item.label}</p>
                          </div>
                          <div className="flex items-baseline gap-3 mb-4">
                            <span className="text-4xl font-black text-white tracking-tighter">{item.score}</span>
                            <span className="text-xs font-black text-slate-600 uppercase tracking-widest">PTS</span>
                          </div>
                          <div className="h-2.5 bg-slate-900 rounded-full overflow-hidden border border-slate-800/50 shadow-inner">
                            <div className="h-full rounded-full transition-all duration-[2000ms] delay-500"
                              style={{ width: `${item.score}%`, background: `linear-gradient(90deg, ${item.color}, #fff)` }} />
                          </div>
                        </div>
                      ))}
                    </div>
                </div>
              )}
            </div>
          )}

          {/* Jobs Tab */}
          {activeTab === 'jobs' && (
            <div className="animate-fade-in max-w-6xl mx-auto pb-20">
              <div className="mb-14">
                <h2 className="text-5xl font-black text-white tracking-tight uppercase leading-tight">Verified <span className="gradient-text">Openings</span></h2>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                {jobs.map(job => {
                  const hasApplied = appliedJobIds.includes(job.id);
                  const isClosed = job.status === 'closed' || job.applicationsCount >= job.vacancyLimit;
                  return (
                    <div key={job.id} className="glass-card p-10 flex flex-col shadow-2xl hover:scale-[1.02] transition-all duration-500 border border-white/5 hover:border-indigo-500/20">
                      <div className="flex items-start justify-between mb-8">
                        <div className="flex items-center gap-6">
                          <div className="w-16 h-16 rounded-[22px] bg-slate-900 border border-slate-800 flex items-center justify-center text-3xl font-black text-indigo-400 shadow-inner">
                            {job.company.charAt(0)}
                          </div>
                          <div>
                            <h3 className="text-2xl font-black text-white tracking-tight uppercase leading-tight">{job.role}</h3>
                            <p className="text-base text-indigo-400 font-black uppercase tracking-[0.1em] mt-1 opacity-70">{job.company}</p>
                          </div>
                        </div>
                        <span className={`px-5 py-2 rounded-full text-[10px] font-black tracking-widest uppercase shadow-sm ${isClosed ? 'badge-closed' : 'badge-open'}`}>
                          {isClosed ? 'CLOSED' : 'ACTIVE'}
                        </span>
                      </div>
                      <p className="text-base text-slate-400 mb-8 line-clamp-3 leading-relaxed font-medium">{job.description}</p>
                      <div className="grid grid-cols-2 gap-4 mb-10">
                        <div className="bg-slate-900/50 p-4 rounded-[20px] border border-slate-800 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-500 uppercase mb-2">Location</span>
                          <span className="text-xs font-black text-white">📍 {job.location.toUpperCase()}</span>
                        </div>
                        <div className="bg-slate-900/50 p-4 rounded-[20px] border border-slate-800 flex flex-col items-center">
                          <span className="text-[10px] font-black text-slate-500 uppercase mb-2">Compensation</span>
                          <span className="text-xs font-black text-white">💰 {job.salary}</span>
                        </div>
                      </div>
                      <div className="mt-auto">
                        <button onClick={() => !hasApplied && !isClosed && handleApply(job.id)} disabled={hasApplied || isClosed}
                          className={`w-full py-5 rounded-[22px] text-sm font-black uppercase tracking-[0.2em] flex items-center justify-center gap-4 shadow-2xl transition-all ${
                            hasApplied ? 'bg-emerald-500/10 border border-emerald-500/30 text-emerald-400' :
                            isClosed ? 'bg-red-500/10 border border-red-500/30 text-red-400' : 'glow-btn'
                          }`}>
                          {hasApplied ? <><CheckCircle className="w-5 h-5" /> VERIFIED</> : isClosed ? 'PIPELINE CLOSED' : <><Send className="w-5 h-5" /> INITIALIZE</>}
                        </button>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Applications Tab */}
          {activeTab === 'applications' && (
            <div className="animate-fade-in max-w-6xl mx-auto pb-20">
              <div className="mb-14">
                <h2 className="text-5xl font-black text-white tracking-tight uppercase">Active <span className="gradient-text">Pipelines</span></h2>
              </div>
              <div className="glass-card overflow-hidden shadow-2xl border border-white/5">
                <table className="data-table">
                  <thead>
                    <tr>
                      <th className="tracking-[0.25em]">ROLE INDEX</th>
                      <th className="tracking-[0.25em]">ENTITY</th>
                      <th className="tracking-[0.25em]">PIPELINE STATUS</th>
                      <th className="tracking-[0.25em]">RANK SCORE</th>
                    </tr>
                  </thead>
                  <tbody>
                    {myApps.map(app => (
                        <tr key={app.id}>
                          <td className="font-black text-white text-lg tracking-tight uppercase">{app.job?.role || 'SYSTEM_ERR'}</td>
                          <td className="text-slate-300 font-bold uppercase tracking-widest opacity-60">{app.job?.company || 'N/A'}</td>
                          <td>
                            <span className={`px-6 py-2.5 rounded-full text-xs font-black tracking-widest uppercase shadow-sm flex items-center w-fit gap-2.5 badge-${app.status}`}>
                              {app.status}
                            </span>
                          </td>
                          <td className="font-black text-indigo-400 text-3xl tracking-tighter">{app.scores?.finalScore || '—'}</td>
                        </tr>
                      ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
}
